import React, { useEffect, useRef, useState } from "react";
import AOS from "aos";
import "aos/dist/aos.css";

const skillData = [
  {
    category: "Languages & Core",
    skills: [
      { name: "PHP", level: 90 },
      { name: "JavaScript", level: 75 },
      { name: "Python", level: 65 },
    ]
  },
  {
    category: "Frameworks",
    skills: [
      { name: "Symfony", level: 85 },
      { name: "Laravel", level: 80 },
      { name: "Node.js", level: 65 },
      { name: "Django", level: 60 },
    ]
  },
  {
    category: "Frontend",
    skills: [
      { name: "React", level: 60 },
      { name: "HTML/CSS", level: 85 },
      { name: "Twig/Smarty", level: 90 },
    ]
  },
  {
    category: "DevOps & DB",
    skills: [
      { name: "MySQL/PostgreSQL", level: 85 },
      { name: "AWS (EC2)", level: 70 },
      { name: "GIT", level: 80 },
    ]
  }
];

const Skills = () => {
  const skillsRef = useRef(null);
  const [isVisible, setIsVisible] = useState(false);

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) setIsVisible(true);
      },
      { threshold: 0.2 }
    );
    if (skillsRef.current) observer.observe(skillsRef.current);
    return () => observer.disconnect();
  }, []);

  return (
    <section ref={skillsRef} id="skills" className="skills section">
      <div className="container section-title" data-aos="fade-up">
        <h2 className="text-gradient">Technical Expertise</h2>
        <p>I am a fast learner with a strong ability to adapt to new technologies and frameworks efficiently. My passion for problem-solving enables me to quickly implement technical solutions.</p>
      </div>

      <div className="container">
        <div className="row g-5">
          {skillData.map((group, idx) => (
            <div key={idx} className="col-lg-6" data-aos="fade-up" data-aos-delay={idx * 100}>
              <div className="skill-group glass-effect p-4 h-100" style={{ borderRadius: '20px' }}>
                <h4 className="mb-4 text-gradient">{group.category}</h4>
                {group.skills.map((skill, sIdx) => (
                  <div key={sIdx} className="skill-item mb-4">
                    <div className="skill-header">
                      <span className="fw-bold">{skill.name}</span>
                      <span className="text-muted">{skill.level}%</span>
                    </div>
                    <div className="progress-container mt-2">
                      <div 
                        className="progress-bar" 
                        style={{ 
                          width: isVisible ? `${skill.level}%` : '0%',
                          transition: 'width 1.5s cubic-bezier(0.4, 0, 0.2, 1)' 
                        }}
                      ></div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
};

export default Skills;
